//-------------------- KONFIGURASI DASAR -----------------------------//
const url = "http://172.16.1.2:7547";
const informInterval = 3600;

const daily = Date.now(86400000);
const update = Date.now(60000); // 1 Menit untuk refresh parameter

//-------------------- AUTH KE ACS (CPE -> ACS) ----------------------//
const AcsUser = "admin";
const AcsPass = "admin";

//-------------------- CONN REQ (ACS -> CPE) -------------------------//
// Menggunakan 8 digit terakhir Serial Number sebagai password agar UNIK tapi TETAP (statis)
// Minimal 8 digit diperlukan untuk menghindari error cwmp:9002 pada modem ZTE/Huawei
let sn = declare("DeviceID.SerialNumber", {value: daily}).value[0];
const ConnReqUser = "admin";
let ConnReqPass = sn ? sn : "admin123";
if (ConnReqPass.length < 8) {
    ConnReqPass = (ConnReqPass + "12345678").slice(0, 8);
} else {
    ConnReqPass = ConnReqPass.slice(-8);
}

//-------------------- IDENTIFIKASI BRAND ----------------------------//
const brand = declare('DeviceID.Manufacturer', {value: daily}).value[0];

if (brand !== "MikroTik") {
    // Jalur TR-069 Standar (ZTE, Huawei, Fiberhome, dll)
    declare("InternetGatewayDevice.ManagementServer.Username", {value: daily}, {value: AcsUser});
    declare("InternetGatewayDevice.ManagementServer.Password", {value: daily}, {value: AcsPass});
    declare("InternetGatewayDevice.ManagementServer.ConnectionRequestUsername", {value: daily}, {value: ConnReqUser});
    declare("InternetGatewayDevice.ManagementServer.ConnectionRequestPassword", {value: daily}, {value: ConnReqPass});
    declare("InternetGatewayDevice.ManagementServer.PeriodicInformEnable", {value: daily}, {value: true});
    declare("InternetGatewayDevice.ManagementServer.PeriodicInformInterval", {value: daily}, {value: informInterval});
    declare("InternetGatewayDevice.ManagementServer.URL", {value: daily}, {value: url});
} else {
    // Jalur MikroTik
    declare("Device.ManagementServer.Username", {value: daily}, {value: AcsUser});
    declare("Device.ManagementServer.Password", {value: daily}, {value: AcsPass});
    declare("Device.ManagementServer.PeriodicInformEnable", {value: daily}, {value: true});
    declare("Device.ManagementServer.PeriodicInformInterval", {value: daily}, {value: informInterval});
    declare("Device.ManagementServer.URL", {value: daily}, {value: url});
}

const now = Date.now();

// Clear cached data model to force a refresh
clear("Device", now);
clear("InternetGatewayDevice", now);

const hourly = Date.now(3600000);

// Refresh basic parameters hourly
declare("InternetGatewayDevice.DeviceInfo.HardwareVersion", {path: hourly, value: hourly});
declare("InternetGatewayDevice.DeviceInfo.SoftwareVersion", {path: hourly, value: hourly});
declare("InternetGatewayDevice.WANDevice.*.WANConnectionDevice.*.WANIPConnection.*.MACAddress", {path: hourly, value: hourly});
declare("InternetGatewayDevice.WANDevice.*.WANConnectionDevice.*.WANIPConnection.*.ExternalIPAddress", {path: hourly, value: hourly});
declare("InternetGatewayDevice.LANDevice.*.WLANConfiguration.*.SSID", {path: hourly, value: hourly});
// Don't refresh password field periodically because CPEs always report blank passowrds for security reasons
declare("InternetGatewayDevice.LANDevice.*.WLANConfiguration.*.KeyPassphrase", {path: hourly, value: 1});
declare("InternetGatewayDevice.LANDevice.*.Hosts.Host.*.HostName", {path: hourly, value: hourly});
declare("InternetGatewayDevice.LANDevice.*.Hosts.Host.*.IPAddress", {path: hourly, value: hourly});
declare("InternetGatewayDevice.LANDevice.*.Hosts.Host.*.MACAddress", {path: hourly, value: hourly});

// Set penggantian useradmin dan superadmin secara otomatis

// variable user dan password user admin silahkan ganti dengan user yang anda mau
//const user = "user";
//const userpw = "user";

// variable user dan password super admin silahkan ganti dengan user yang anda mau
//const superuser = "admin@kimz";
//const superpw = "admin@kimz";

// Refresh Harian
const daily = Date.now(86400000);

// UNCOMMENT (hapus // ) dibawah ini untuk mengaktifkan penggantian USER ADMIN secara otomatis
//declare("VirtualParameters.userAdmin", {value: daily}, {value: user});
//declare("VirtualParameters.userPassword", {value: daily}, {value: userpw});

// UNCOMMENT (hapus // ) dibawah ini untuk mengaktifkan penggantian SUPER ADMIN secara otomatis
//declare("VirtualParameters.superAdmin", {value: daily}, {value: superuser});
//declare("VirtualParameters.superPassword", {value: daily}, {value: superpw});

//-----NOT-FOR-RESALLE----------------0896-7611-6136-----------NOT-FOR-RESALLE-----------//

const now = Date.now();

// Paksa isi Username dan Password dengan nilai yang pasti ("admin").
// Password harus minimal 8 karakter agar tidak ditolak oleh firmware Huawei/ZTE (cwmp:9002).
declare("InternetGatewayDevice.ManagementServer.ConnectionRequestUsername", {value: now}, {value: "admin"});
declare("InternetGatewayDevice.ManagementServer.ConnectionRequestPassword", {value: now}, {value: "admin123"});
